export default function Certificates() {
  const data = [
    {
      name: "Introduction to Japanese Language and Culture",
      provider: "NPTEL • IIT Kanpur",
    },
    {
      name: "Web Design for Everybody: Basics of Web Development & Coding",
      provider: "Coursera • University of Michigan",
    },
    {
      name:
        "Marugoto A1-1 (Katsudoo & Rikai) Self-Study Course (KC20_MGRS_A101_EN01)",
      provider: "Minato • JF Japanese e-Learning",
    },
  ];

  return (
    <section
      id="certificates"
      className="h-screen flex flex-col justify-evenly"
    >
      <div className="section-title flex self-center">Certificates</div>

      <div className="flex flex-col justify-evenly space-y-6 self-center">
        {data.map((item, index) => (
          <div key={index} className="flex flex-row space-x-8 items-center">
            <img
              alt="Medal icon"
              src="https://img.icons8.com/plasticine/2x/medal.png"
              style={{ height: 48, width: 48 }}
            />
            <div className="flex flex-col space-y-2">
              <div className="text-gray-600">{item.name}</div>
              <div className="text-gray-500">{item.provider}</div>
            </div>
          </div>
        ))}
      </div>
    </section>
  );
}
